"},"$:/plugins/wikilabs/link-to-tabs/styles":{"title":"$:/plugins/wikilabs/link-to-tabs/styles","created":"20190712133348541","modified":"20190714104306483","tags":"$:/tags/Stylesheet","type":"text/vnd.tiddlywiki","text":"<pre>

.wltc-link-to-tab {
  display: {{$:/plugins/wikilabs/link-to-tabs/config!!show-all-links}};
  position: relative;
  top: -1em;
  left: -1.3em;
  font-size: 0.7em;
  opacity: {{$:/plugins/wikilabs/link-to-tabs/config!!initial-opacity}};
  margin-right: -1em;
}

.wltc-link-to-tab svg{
  width: 1.4em;
  height: 1.4em;
}

.wltc-link-to-tab:hover {
  opacity: 1;
  transition:opacity {{$:/plugins/wikilabs/link-to-tabs/config!!transition}}s;
  transition-timing-function: cubic-bezier(1,-0.06,.39,.89);
}

.tc-tab-selected + .wltc-link-to-tab {
  display: {{$:/plugins/wikilabs/link-to-tabs/config!!show-single-link}};
}

.tc-vertical > .wltc-link-to-tab {
  top: -1.9em;
  left: 0;
  height: 0;
  float: right;
}

.tc-search-results .wltc-link-to-tab a {
  display: contents;
  padding: 0;
}

</pre>"},"$:/plugins/wikilabs/link-to-tabs/readme":{"title":"$:/plugins/wikilabs/link-to-tabs/readme","text":"This plugin adds a little link icon to every tab.

